import pandas as pd
import numpy as np

def compute_baselines(incidents: list[dict]) -> dict:
    df = pd.DataFrame(incidents)
    df["created_at"] = pd.to_datetime(df["created_at"])

    # Rolling 90-day window
    cutoff = pd.Timestamp.utcnow() - pd.Timedelta(days=90)
    recent = df[df["created_at"] >= cutoff].copy()

    # Compute duration fields
    for col_pair in [("failure_onset", "detected_at", "mttd_min"),
                     ("detected_at", "acknowledged_at", "mtta_min"),
                     ("failure_onset", "mitigated_at", "mttr_min")]:
        t0, t1, name = col_pair
        recent[name] = (
            pd.to_datetime(recent[t1]) - pd.to_datetime(recent[t0])
        ).dt.total_seconds() / 60

    baselines = {}
    for sev in ["SEV-1", "SEV-2", "SEV-3"]:
        subset = recent[recent["severity"] == sev]
        if len(subset) < 5:
            continue  # not enough data for reliable percentiles
        baselines[sev] = {
            metric: {
                "p50": float(np.percentile(subset[metric].dropna(), 50)),
                "p90": float(np.percentile(subset[metric].dropna(), 90)),
                "n": len(subset[metric].dropna()),
            }
            for metric in ["mttd_min", "mtta_min", "mttr_min"]
        }

    return baselines

